func HasSession() predicate.UxQuestionnaireAnswer {
	return predicate.UxQuestionnaireAnswer(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, SessionTable, SessionColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasSessionWith applies the HasEdge predicate on the "session" edge with a given conditions (other predicates).
func HasSessionWith(preds ...predicate.UxExecutionSession) predicate.UxQuestionnaireAnswer {
	return predicate.UxQuestionnaireAnswer(func(s *sql.Selector) {
		step := newSessionStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.UxQuestionnaireAnswer) predicate.UxQuestionnaireAnswer {
	return predicate.UxQuestionnaireAnswer(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.UxQuestionnaireAnswer) predicate.UxQuestionnaireAnswer {
	return predicate.UxQuestionnaireAnswer(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.UxQuestionnaireAnswer) predicate.UxQuestionnaireAnswer {
	return predicate.UxQuestionnaireAnswer(sql.NotPredicates(p))
}
